 class PtyCreateTool(Tool):
     """Create a new PTY session."""

     def __init__(self):
         super().__init__(
             name="pty_create",
             description="Create a new PTY (pseudo-terminal) session",
         )
         self.parameters = {
             "type": "object",
             "properties": {
                 "command": {
                     "type": "string",
                     "description": "Shell command to run (default: system shell)",
                 },
                 "args": {
                     "type": "array",
                     "items": {"type": "string"},
                     "description": "Command arguments",
                 },
                 "cwd": {"type": "string", "description": "Working directory"},
                 "title": {"type": "string", "description": "Terminal title"},
                 "rows": {
                     "type": "integer",
                     "default": 24,
                     "description": "Terminal rows",
                 },
                 "cols": {
                     "type": "integer",
                     "default": 80,
                     "description": "Terminal columns",
                 },
             },
         }

     async def execute(
         self,
         command: str = None,
         args: list = None,
         cwd: str = None,
         title: str = None,
         rows: int = 24,
         cols: int = 80,
     ) -> ToolResult:
         """Create a new PTY session."""
         try:
             from nanocode.pty import PtyManager

             info = await PtyManager.create(
                 command=command,
                 args=args,
                 cwd=cwd,
                 title=title,
             )

             await PtyManager.resize(info.id, cols, rows)

             return ToolResult(
                 success=True,
                 content={
                     "id": info.id,
                     "title": info.title,
                     "command": info.command,
                     "cwd": info.cwd,
                     "pid": info.pid,
                     "status": info.status.value,
                 },
             )
         except Exception as e:
             return ToolResult(success=False, content=None, error=str(e))


